class Solution:
    def minFallingPathSum(self, matrix: list[list[int]]) -> int:
        n = len(matrix)
        if n == 0:
            return 0

        # We can modify the matrix in-place to store DP values, saving space.
        # matrix[r][c] will store the minimum falling path sum to reach that cell.

        for r in range(1, n):
            for c in range(n):
                # Calculate the minimum from the eligible parents in the previous row (r-1)
                min_prev_row_val = float('inf')

                # Parent from top-left (matrix[r-1][c-1])
                if c > 0:
                    min_prev_row_val = min(min_prev_row_val, matrix[r-1][c-1])

                # Parent from top (matrix[r-1][c])
                min_prev_row_val = min(min_prev_row_val, matrix[r-1][c])

                # Parent from top-right (matrix[r-1][c+1])
                if c < n - 1:
                    min_prev_row_val = min(min_prev_row_val, matrix[r-1][c+1])

                # Update the current cell with the minimum falling path sum to reach it
                matrix[r][c] += min_prev_row_val

        # The minimum falling path sum will be the minimum value in the last row of the modified matrix
        return min(matrix[n-1])
